import React, { useState, useEffect } from 'react';
import {
  BarChart, Bar, LineChart, Line,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend,
  PieChart, Pie, Cell, ResponsiveContainer,
} from 'recharts';
import reportService from '../../services/reportService';
import Card from '../../components/common/Card';
import Spinner from '../../components/common/Spinner';
import Alert from '../../components/common/Alert';
import { Select } from '../../components/common/Input';
import { formatCurrency, formatHours, monthLabel } from '../../utils/formatters';
import { MONTHS_RO } from '../../constants';
import './ReportsPage.css';

const CHART_COLORS = ['#1e3a5f', '#0ea5e9', '#22c55e', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4'];

const currentYear = new Date().getFullYear();
const currentMonth = new Date().getMonth() + 1;

const yearOptions = Array.from({ length: 5 }, (_, i) => ({
  value: String(currentYear - i), label: String(currentYear - i),
}));

const monthOptions = [
  { value: '', label: 'Tot anul' },
  ...MONTHS_RO.map((m, i) => ({ value: String(i + 1), label: m })),
];

const TABS = [
  { id: 'summary', label: 'Sumar' },
  { id: 'attendance', label: 'Prezență' },
  { id: 'salary', label: 'Salarii' },
  { id: 'departments', label: 'Departamente' },
];

export default function ReportsPage() {
  const [year, setYear] = useState(String(currentYear));
  const [month, setMonth] = useState(String(currentMonth));
  const [tab, setTab] = useState('summary');
  const [data, setData] = useState({});
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      setError('');
      try {
        const params = { year, ...(month ? { month } : {}) };
        const [summary, attendance, salary, departments] = await Promise.all([
          reportService.getSummary(params),
          reportService.getAttendance(params),
          reportService.getSalary(params),
          reportService.getDepartments(params),
        ]);
        setData({
          summary: summary.data?.data || summary.data,
          attendance: attendance.data?.data || attendance.data,
          salary: salary.data?.data || salary.data,
          departments: departments.data?.data || departments.data,
        });
      } catch {
        setError('Eroare la încărcarea rapoartelor.');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [year, month]);

  return (
    <div className="reports-page">
      <div className="reports-header">
        <div>
          <h1>Rapoarte</h1>
          <p className="text-muted">Statistici și analize HR</p>
        </div>
        <div className="reports-filters">
          <Select
            value={year}
            onChange={e => setYear(e.target.value)}
            options={yearOptions}
          />
          <Select
            value={month}
            onChange={e => setMonth(e.target.value)}
            options={monthOptions}
          />
        </div>
      </div>

      <div className="reports-tabs">
        {TABS.map(t => (
          <button
            key={t.id}
            className={`tab-btn ${tab === t.id ? 'active' : ''}`}
            onClick={() => setTab(t.id)}
          >
            {t.label}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="reports-loading"><Spinner /></div>
      ) : error ? (
        <Alert type="danger">{error}</Alert>
      ) : (
        <>
          {tab === 'summary' && <SummaryTab data={data.summary} />}
          {tab === 'attendance' && <AttendanceTab data={data.attendance} />}
          {tab === 'salary' && <SalaryTab data={data.salary} />}
          {tab === 'departments' && <DepartmentsTab data={data.departments} />}
        </>
      )}
    </div>
  );
}

/* ─── Sub-tabs ─────────────────────────────────────────────────── */

function SummaryTab({ data }) {
  if (!data) return <Empty />;
  const stats = [
    { label: 'Total angajați', value: data.totalEmployees ?? '—' },
    { label: 'Angajați activi', value: data.activeEmployees ?? '—' },
    { label: 'Zile prezență', value: data.totalPresentDays ?? '—' },
    { label: 'Cereri concediu', value: data.totalLeaveRequests ?? '—' },
    { label: 'Fond salarii', value: data.totalSalaryFund ? formatCurrency(data.totalSalaryFund) : '—' },
    { label: 'Ore overtime', value: data.totalOvertimeHours ? formatHours(data.totalOvertimeHours) : '—' },
  ];
  return (
    <div className="stat-grid">
      {stats.map((s, i) => (
        <Card key={i}>
          <Card.Body className="stat-cell">
            <div className="stat-value">{s.value}</div>
            <div className="stat-label">{s.label}</div>
          </Card.Body>
        </Card>
      ))}
    </div>
  );
}

function AttendanceTab({ data }) {
  if (!data) return <Empty />;
  const rows = Array.isArray(data) ? data : (data.rows || []);
  const chartData = rows.slice(0, 12).map(r => ({
    name: r.date || r.name || r.month,
    Prezent: r.present || r.presentCount || 0,
    Absent: r.absent || r.absentCount || 0,
    Ore: r.totalHours ? Math.round(r.totalHours) : 0,
  }));

  return (
    <div className="reports-section">
      {chartData.length > 0 && (
        <Card>
          <Card.Header><h3>Prezență zilnică</h3></Card.Header>
          <Card.Body>
            <ResponsiveContainer width="100%" height={280}>
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                <YAxis tick={{ fontSize: 12 }} />
                <Tooltip />
                <Legend />
                <Bar dataKey="Prezent" fill="#22c55e" radius={[4,4,0,0]} />
                <Bar dataKey="Absent" fill="#ef4444" radius={[4,4,0,0]} />
              </BarChart>
            </ResponsiveContainer>
          </Card.Body>
        </Card>
      )}
      <DataTable rows={rows} columns={['date', 'present', 'absent', 'totalHours']}
        headers={['Dată', 'Prezenți', 'Absenți', 'Ore totale']} />
    </div>
  );
}

function SalaryTab({ data }) {
  if (!data) return <Empty />;
  const rows = Array.isArray(data) ? data : (data.rows || []);
  const chartData = rows.slice(0, 12).map(r => ({
    name: r.month ? `${MONTHS_RO[(r.month || 1) - 1]} ${r.year || ''}` : (r.name || ''),
    Brut: r.totalGross || r.grossSalary || 0,
    Net: r.totalNet || r.netSalary || 0,
  }));

  return (
    <div className="reports-section">
      {chartData.length > 0 && (
        <Card>
          <Card.Header><h3>Evoluție fond salarii</h3></Card.Header>
          <Card.Body>
            <ResponsiveContainer width="100%" height={280}>
              <LineChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" />
                <XAxis dataKey="name" tick={{ fontSize: 12 }} />
                <YAxis tick={{ fontSize: 12 }} tickFormatter={v => `${(v/1000).toFixed(0)}k`} />
                <Tooltip formatter={v => formatCurrency(v)} />
                <Legend />
                <Line type="monotone" dataKey="Brut" stroke="#1e3a5f" strokeWidth={2} dot={{ r: 4 }} />
                <Line type="monotone" dataKey="Net" stroke="#22c55e" strokeWidth={2} dot={{ r: 4 }} />
              </LineChart>
            </ResponsiveContainer>
          </Card.Body>
        </Card>
      )}
      <DataTable rows={rows}
        columns={['month', 'year', 'totalGross', 'totalNet', 'employeeCount']}
        headers={['Luna', 'An', 'Total Brut', 'Total Net', 'Angajați']}
        formatters={{ totalGross: formatCurrency, totalNet: formatCurrency }} />
    </div>
  );
}

function DepartmentsTab({ data }) {
  if (!data) return <Empty />;
  const rows = Array.isArray(data) ? data : (data.departments || []);

  return (
    <div className="reports-section">
      {rows.length > 0 && (
        <Card>
          <Card.Header><h3>Distribuție angajați pe departamente</h3></Card.Header>
          <Card.Body className="dept-chart-body">
            <ResponsiveContainer width="100%" height={280}>
              <PieChart>
                <Pie data={rows} dataKey="employeeCount" nameKey="name" cx="50%" cy="50%" outerRadius={100} label>
                  {rows.map((_, i) => <Cell key={i} fill={CHART_COLORS[i % CHART_COLORS.length]} />)}
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </Card.Body>
        </Card>
      )}
      <DataTable rows={rows}
        columns={['name', 'employeeCount', 'averageSalary']}
        headers={['Departament', 'Angajați', 'Salariu mediu']}
        formatters={{ averageSalary: formatCurrency }} />
    </div>
  );
}

function DataTable({ rows = [], columns, headers, formatters = {} }) {
  if (!rows.length) return null;
  return (
    <Card>
      <div className="table-wrapper">
        <table className="data-table">
          <thead>
            <tr>{headers.map((h, i) => <th key={i}>{h}</th>)}</tr>
          </thead>
          <tbody>
            {rows.map((row, ri) => (
              <tr key={ri}>
                {columns.map((col, ci) => (
                  <td key={ci}>
                    {formatters[col] ? formatters[col](row[col]) : (row[col] ?? '—')}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </Card>
  );
}

function Empty() {
  return <Card><Card.Body className="text-center text-muted p-2">Nu există date disponibile.</Card.Body></Card>;
}
